import React from 'react';
import { Trash2, CheckCircle, Clock } from 'lucide-react';
import axios from 'axios';

const TaskCard = ({ task, refreshTasks }) => {
  const userRole = localStorage.getItem('role');
  const token = localStorage.getItem('token');

  const updateStatus = async (newStatus) => {
    try {
      await axios.patch(`http://localhost:5000/api/tasks/${task._id}`, 
        { status: newStatus },
        { headers: { 'x-auth-token': token } }
      );
      refreshTasks();
    } catch (err) { alert("Status update failed"); }
  };

  const deleteTask = async () => {
    try {
      await axios.delete(`http://localhost:5000/api/tasks/${task._id}`, {
        headers: { 'x-auth-token': token }
      });
      refreshTasks();
    } catch (err) { alert("Delete failed"); }
  };

  return (
    <div className="p-6 bg-white/5 border border-white/10 rounded-3xl backdrop-blur-lg">
      <div className="flex justify-between items-start mb-4">
        <h3 className="text-xl font-bold text-white">{task.title}</h3>
        {userRole === 'admin' && (
          <button onClick={deleteTask} className="text-red-500 hover:text-red-400 p-2">
            <Trash2 size={18} />
          </button>
        )}
      </div>
      <p className="text-gray-400 text-sm mb-6">{task.description}</p>
      
      <div className="flex items-center justify-between">
        <span className={`text-[10px] px-3 py-1 rounded-full ${task.status === 'Completed' ? 'bg-green-500/20 text-green-400' : 'bg-yellow-500/20 text-yellow-400'}`}>
          {task.status}
        </span>

        {/* Member Status Update Button */}
        {userRole === 'member' && task.status !== 'Completed' && (
          <button 
            onClick={() => updateStatus('Completed')}
            className="flex items-center gap-2 bg-green-600 px-4 py-2 rounded-xl text-xs font-bold"
          >
            <CheckCircle size={14} /> Mark Done
          </button>
        )}
      </div>
    </div>
  );
};

export default TaskCard;
